#!/usr/bin/env python3
from typing import Dict, Any, List
from plugins.common.plugin_entry import nv_enrich_plugin
from plugins.common.segmentation_utils import (
    compute_area_ratio_per_segment,
    aggregate_area_ratio_by_class,
)

@nv_enrich_plugin("segmentation_area_ratio", result_scope="frame")
def process_job(job: Dict[str, Any]) -> Dict[str, Any]:
    """
    Calcula:
      1) Porcentaje de área (0-100) por segmento detectado → lista preservando el orden
      2) Porcentaje de área (0-100) agregado por clase → dict

    Entrada esperada en `job`:
      - frame: dict (no se usa directamente, pero es requerido por el decorador)
      - detections: List[ { detection_id, class_name, ... } ]
      - segmentations: List[ { detection_id, mask_area (0-1 opcional), mask_data opcional } ]

    Salida:
      {
        "segments_area_percent": [
          {"detection_id": 123, "class_name": "person", "percent": 33.0},
          {"detection_id": 124, "class_name": "person", "percent": 31.0},
          {"detection_id": 125, "class_name": "tv",     "percent": 15.0}
        ],
        "area_percent_by_class": {
          "person": 64.0,
          "tv": 15.0
        }
      }
    """
    frame = job.get("frame")
    detections: List[Dict[str, Any]] = job.get("detections", []) or []
    segmentations: List[Dict[str, Any]] = job.get("segmentations", []) or []

    # Si no hay frame o segmentaciones, no procesamos
    if not frame or not segmentations:
        return {}

    # Mapa detection_id → class_name (preferimos el de la detección oficial)
    det2class: Dict[Any, str] = {}
    for d in detections:
        det_id = d.get("detection_id") or d.get("id")
        if det_id is not None:
            det2class[det_id] = d.get("class_name", "unknown")

    # 1) % por segmento (preserva orden de segmentations)
    segments_area_percent = compute_area_ratio_per_segment(segmentations, det2class, round_digits=2)

    # 2) % agregado por clase (sumatoria de porcentajes por clase)
    area_percent_by_class = aggregate_area_ratio_by_class(segments_area_percent, round_digits=2)

    return {
        "segments_area_percent": segments_area_percent,
        "area_percent_by_class": area_percent_by_class,
    }
